using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train and save the model at startup
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");

var dataView = mlContext.Data.LoadFromTextFile<ChurnInput>(dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features", nameof(ChurnInput.Age), nameof(ChurnInput.Income), "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(ChurnInput.Churned),
        featureColumnName: "Features"));

var model = pipeline.Fit(dataView);

// Evaluate on training data (use a larger dataset with TrainTestSplit in production)
var predictions = model.Transform(dataView);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: nameof(ChurnInput.Churned));
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}");

mlContext.Model.Save(model, dataView.Schema, modelPath);

// Register PredictionEnginePool (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST to /predict");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnPrediction> pool, ChurnRequest request) =>
{
    var input = new ChurnInput
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability
    });
});

app.Run();

// --- Models ---

public class ChurnInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Churned")] public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

